const items = $input.all();
const pos = items.map(i => i.json);
const count = pos.length;
if (count === 0) return [{ json: { count: 0, subject: '', htmlBody: '' } }];
const rows = pos.map(p => {
  const sup = (p.supplier && p.supplier.companyName) ? p.supplier.companyName : '-';
  const email = (p.supplier && p.supplier.email) ? p.supplier.email : '-';
  const total = parseFloat(p.total || 0).toFixed(2);
  return `<tr><td style='padding:8px;border-bottom:1px solid #eee'>${p.poNumber}</td><td style='padding:8px;border-bottom:1px solid #eee'>${sup}</td><td style='padding:8px;border-bottom:1px solid #eee'>${email}</td><td style='padding:8px;border-bottom:1px solid #eee'>$${total}</td><td style='padding:8px;border-bottom:1px solid #eee'>${p.orderDate}</td></tr>`;
}).join('');
const htmlBody = `<h2 style='color:#1e3a5f'>PO Confirmation Follow-up</h2><p><strong>${count}</strong> purchase order(s) sent more than 3 days ago and still awaiting supplier confirmation. Please follow up with the relevant suppliers.</p><table style='border-collapse:collapse;width:100%;font-family:Arial,sans-serif;font-size:13px'><thead><tr style='background:#1e3a5f;color:white'><th style='padding:8px;text-align:left'>PO Number</th><th style='padding:8px;text-align:left'>Supplier</th><th style='padding:8px;text-align:left'>Contact Email</th><th style='padding:8px;text-align:left'>Total</th><th style='padding:8px;text-align:left'>Order Date</th></tr></thead><tbody>${rows}</tbody></table><p style='color:#666;font-size:12px;margin-top:16px'>TSH Accounts Payable System — Auto-generated</p>`;
const subject = `[TSH AP] ${count} PO${count > 1 ? 's' : ''} Awaiting Supplier Confirmation`;
return [{ json: { count, subject, htmlBody } }];
